#!/usr/bin/env bash
set -euo pipefail

BALLS_DIR="$(dirname "$0")/../public/assets/balls"
ITEMS_DIR="$(dirname "$0")/../public/assets/items"

mkdir -p "$BALLS_DIR" "$ITEMS_DIR"

download() {
  local id="$1" url="$2" dest="$3"
  local file="$dest/$id.png"
  if [[ -f "$file" ]]; then
    echo "skip $id (exists)"
    return
  fi
  echo "download $id ..."
  if ! curl -fsSL --max-time 15 -o "$file" "$url"; then
    echo "FAIL $id: $url" >&2
    rm -f "$file"
  fi
}

